+  // the result is non-negative.
+  const APInt *C1;
+  bool Match = false;
+  APInt WideC1;
+  if (match(Op0, m_ZExt(m_NSWAddLike(m_Value(X), m_APInt(C1)))) &&
+      cast<ZExtInst>(Op0)->hasNonNeg()) {
+    WideC1 = C1->sext(Ty->getScalarSizeInBits());
+    Match = true;
+  } else if (match(Op0, m_ZExt(m_c_Add(m_Value(X), m_APInt(C1)))) &&
+             cast<ZExtInst>(Op0)->hasNonNeg()) {
+    WideC1 = C1->sext(Ty->getScalarSizeInBits());
+    Match = true;
+  } else if (match(Op0, m_ZExt(m_Sub(m_Value(X), m_APInt(C1)))) &&
+             cast<ZExtInst>(Op0)->hasNonNeg()) {
+    WideC1 = -C1->sext(Ty->getScalarSizeInBits());
+    Match = true;
+  }
+  if (Match && WideC1 + *C == 0)
+    return CastInst::Create(Instruction::SExt, X, Ty);
